(function () {

    const dots = document.querySelectorAll('[data-dot]');

    const swiper = new Swiper(".swiper", {

        spaceBetween: 16,
        slidesPerGroup: 1,

        breakpoints: {
            320: {
                slidesPerView: 1,
                spaceBetween: 30,
            },

            576: {
                slidesPerView: 2,
                spaceBetween: 16,
            },

            768: {
                slidesPerView: 3,
                spaceBetween: 16,
            },
        },
        pagination: {
            el: '.swiper-pagination',
            clickable: true,
        },
        navigation: {
            nextEl: '.swiper-button-next',
            prevEl: '.swiper-button-prev',
        },

    });


})();